package main

import (
	"math/bits"
)

func solve(nums []int64, queries [][]int64) []int64 {
	memo := make(map[int64]int64)

	var getDepth func(x int64) int64
	getDepth = func(x int64) int64 {
		if x == 1 {
			return 0
		}
		if depth, exists := memo[x]; exists {
			return depth
		}
		next := int64(bits.OnesCount64(uint64(x)))
		depth := 1 + getDepth(next)
		memo[x] = depth
		return depth
	}

	depth := make([]int64, len(nums))
	for i, num := range nums {
		depth[i] = getDepth(num)
	}

	answer := make([]int64, 0)

	for _, query := range queries {
		if query[0] == 1 {
			l := query[1]
			r := query[2]
			k := query[3]
			count := int64(0)
			for i := l; i <= r; i++ {
				if depth[i] == k {
					count++
				}
			}
			answer = append(answer, count)
		} else if query[0] == 2 {
			idx := query[1]
			val := query[2]
			nums[idx] = val
			depth[idx] = getDepth(val)
		}
	}

	return answer
}
