package main

import (
	"math/bits"
)

func solve(nums []int64, queries [][]int64) []int64 {
	memo := make(map[int64]int64)

	var getDepth func(x int64) int64
	getDepth = func(x int64) int64 {
		if x == 1 {
			return 0
		}
		if depth, exists := memo[x]; exists {
			return depth
		}
		next := popcount(x)
		depth := 1 + getDepth(next)
		memo[x] = depth
		return depth
	}

	depths := make([]int64, len(nums))
	for i, num := range nums {
		depths[i] = getDepth(num)
	}

	answer := make([]int64, 0)

	for _, query := range queries {
		if query[0] == 1 {
			l := query[1]
			r := query[2]
			k := query[3]
			count := int64(0)
			for i := l; i <= r; i++ {
				if depths[i] == k {
					count++
				}
			}
			answer = append(answer, count)
		} else if query[0] == 2 {
			idx := query[1]
			val := query[2]
			nums[idx] = val
			depths[idx] = getDepth(val)
		}
	}

	return answer
}

func popcount(x int64) int64 {
	return int64(bits.OnesCount64(uint64(x)))
}
